mapper.select:
SELECT id::text, user_id::text, session_id, seq_start_no, seq_end_no,
       status, error_message, created_at, updated_at
FROM memory_extraction_log
WHERE session_id = #{sessionId}
  AND seq_start_no = #{seqStartNo}
  AND seq_end_no = #{seqEndNo}

mapper.insert:
INSERT INTO memory_extraction_log (
    user_id, session_id, seq_start_no, seq_end_no, status, error_message
) VALUES (
    CAST(#{userId} AS uuid), #{sessionId}, #{seqStartNo}, #{seqEndNo},
    #{status}, #{errorMessage}
)
